    business_rule_ids: ['br_activity_type_scope', 'br_exclude_front_sc', 'br_exclude_staff_names'],
    sql_template: `SELECT d.dealer_nm, u.group_name, u.dept_nm, u.[name], o.common_tp_nm,\n    SUM(f.actual_cnt) AS ac_cnt\nFROM ktws.FCT_ACTIVITY_v2 AS f\n    INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON f.act_dt_fr = c.[Date]\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS t ON f.tp_key = t.tp_key\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS o ON t.common_tp_nm = o.common_tp_nm\n    INNER JOIN ktws.DIM_MNG_USER AS u ON f.sc_key = u.sc_key\n    INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\nWHERE t.tp_grp_1 IN ('관계형성', '기회창출')\n    AND c.[Year] = 2026 AND c.[MonthNumber] = 4\n    AND d.dealer_nm IS NOT NULL AND LTRIM(RTRIM(d.dealer_nm)) <> ''\n    AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n    AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\nGROUP BY d.dealer_nm, u.group_name, u.dept_nm, u.[name], o.common_tp_nm`,
