    description: '실적/목표 CTE를 5개 키(dealer_nm/group_name/dept_nm/name/common_tp_nm)로 FULL OUTER JOIN, 한쪽만 있어도 0으로 채운 뒤 진행률 계산.',
    input_tables: [], input_columns: [],
    output_columns: ['dealer_nm', 'group_name', 'dept_nm', 'name', 'common_tp_nm', 'act_mtd_ac_preOp', 'act_mtd_target_preOp', 'progress_act_mtd_preOp'],
    dependencies: ['frag_activity_progress_list_ac', 'frag_activity_progress_list_tgt'], business_rule_ids: [],
    sql_template: `SELECT\n    COALESCE(ac.dealer_nm, tgt.dealer_nm) AS dealer_nm,\n    COALESCE(ac.group_name, tgt.group_name) AS group_name,\n    COALESCE(ac.dept_nm, tgt.dept_nm) AS dept_nm,\n    COALESCE(ac.[name], tgt.[name]) AS [name],\n    COALESCE(ac.common_tp_nm, tgt.common_tp_nm) AS common_tp_nm,\n    ISNULL(ac.ac_cnt, 0) AS act_mtd_ac_preOp,\n    ISNULL(tgt.tgt_cnt, 0) AS act_mtd_target_preOp,\n    CASE WHEN tgt.tgt_cnt IS NULL OR tgt.tgt_cnt = 0 THEN 1\n         ELSE CAST(ISNULL(ac.ac_cnt, 0) AS DECIMAL(18,4)) / tgt.tgt_cnt END AS progress_act_mtd_preOp\nFROM activity_progress_list_ac AS ac FULL OUTER JOIN activity_progress_list_tgt AS tgt\n    ON ac.dealer_nm = tgt.dealer_nm AND ac.group_name = tgt.group_name\n    AND ac.dept_nm = tgt.dept_nm AND ac.[name] = tgt.[name] AND ac.common_tp_nm = tgt.common_tp_nm\nORDER BY dealer_nm, group_name, dept_nm, [name], common_tp_nm`,
