    sql_template: `SELECT FORMAT(CAST(C.cnt AS FLOAT) / NULLIF(L.cnt, 0), '0%') AS Percentage\nFROM (\n    SELECT COALESCE(SUM(I.cnt), 0) AS cnt FROM ktws.FCT_CONTRACT_KTWS AS I\n    INNER JOIN mtd_dates AS DT ON I.contract_dt = DT.[Date]\n    INNER JOIN filtered_users_org AS U ON I.cn_sc_key = U.sc_key\n    INNER JOIN lead_pool_coalesce AS LP ON I.lead_key = LP.lead_key\n) AS C\nCROSS JOIN (\n    SELECT COALESCE(SUM(A.target_cnt), 0) AS cnt FROM ktws.FCT_CRM_TARGET_M AS A\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS B ON A.tp_key = B.tp_key\n    INNER JOIN ktws.DIM_CALENDAR_KTWS AS CC ON A.monthly_dt = CC.[Date]\n    INNER JOIN ktws.DIM_MNG_USER AS D ON A.sc_key = D.sc_key\n    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key\n    LEFT JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS F ON B.common_tp_nm = F.common_tp_nm\n    WHERE D.facade_sc_yn <> '창구SC' AND D.name NOT IN ('고객지원팀', 'TOYOTA YM')\n      AND D.user_id NOT IN ('DM5103', 'DM9999', 'JB30016', 'KMKS176', 'KMKS999', 'JB30067')\n      AND B.common_tp_nm = '계약' AND CC.YearMonth = '2026-04' AND D.active_yn = '재직'\n      AND E.dealer_nm = '렉서스 강남' AND D.BRAND = 'LEXUS' AND D.group_name = '렉서스 강서' AND D.dept_nm = '강서영업팀'\n) AS L`,
