    sql_template: `SELECT FORMAT(CAST(T.cnt AS FLOAT) / NULLIF(L.cnt, 0), '0%') AS Percentage\nFROM (\n    SELECT COUNT(DISTINCT ACT.lead_key) AS cnt FROM ktws.FCT_ACTIVITY_v2 AS ACT\n    INNER JOIN mtd_dates AS DT ON ACT.act_dt_fr = DT.[Date]\n    INNER JOIN filtered_users_org AS U ON ACT.sc_key = U.sc_key\n    INNER JOIN testdrive_lead_grp_strict AS LG ON ACT.lead_key = LG.lead_key\n    WHERE ACT.act_tp = 'P113' AND ACT.act_result = '시승완료' AND ACT.lead_key IS NOT NULL\n) AS T\nCROSS JOIN (\n    SELECT COUNT(DISTINCT G.lead_key) AS cnt FROM ktws.FCT_LEAD AS G\n    INNER JOIN ktws.DIM_MNG_USER AS D ON G.cl_sc_key = D.sc_key\n    INNER JOIN ktws.DIM_MNG_DEALER AS E ON D.dealer_key = E.dealer_key\n    INNER JOIN ktws.DIM_CALENDAR_KTWS AS H ON G.lead_reg_dt = H.[Date]\n    WHERE H.YearMonth = '2026-04'\n      AND G.lead_key IN (\n          SELECT ACT.lead_key FROM ktws.FCT_ACTIVITY_v2 AS ACT\n          INNER JOIN ktws.DIM_CRM_ACT_TYPE AS ACT_B ON ACT.tp_key = ACT_B.tp_key\n          WHERE ACT_B.tp_grp_1 IN ('관계형성', '기회창출') AND ACT.act_result <> '부재중'\n      )\n      AND (G.close_dt > EOMONTH('2026-04-30') OR G.close_dt IS NULL OR G.last_retail_sales_dt IS NOT NULL)\n      AND D.facade_sc_yn <> '창구SC' AND D.name NOT IN ('고객지원팀', 'TOYOTA YM')\n      AND D.user_id NOT IN ('DM5103', 'DM9999', 'JB30016', 'KMKS176', 'KMKS999', 'JB30067')\n      AND D.active_yn = '재직' AND E.dealer_nm = '렉서스 강남'\n      AND D.BRAND = 'LEXUS' AND D.group_name = '렉서스 강서' AND D.dept_nm = '강서영업팀'\n) AS L`,
