    sql_template: `SELECT\n    d.dealer_nm, u.group_name, u.dept_nm, u.[name], o.common_tp_nm,\n    COUNT(DISTINCT l.lead_key) AS lead_cnt\nFROM ktws.FCT_LEAD AS l\n    INNER JOIN ktws.DIM_CALENDAR_KTWS AS c ON l.lead_reg_dt = c.[Date]\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS t ON l.tp_key = t.tp_key\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS o ON t.common_tp_nm = o.common_tp_nm\n    INNER JOIN ktws.DIM_MNG_USER AS u ON l.cl_sc_key = u.sc_key\n    INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\nWHERE d.dealer_nm IS NOT NULL AND LTRIM(RTRIM(d.dealer_nm)) <> ''\n    AND EXISTS (\n        SELECT 1 FROM ktws.FCT_ACTIVITY_v2 AS a\n            INNER JOIN ktws.DIM_CRM_ACT_TYPE AS at2 ON a.tp_key = at2.tp_key\n        WHERE a.lead_key = l.lead_key\n            AND at2.tp_grp_1 IN ('관계형성', '기회창출') AND a.act_result <> '부재중'\n    )\n    AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n    AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\nGROUP BY d.dealer_nm, u.group_name, u.dept_nm, u.[name], o.common_tp_nm`,
