    fragment_name: '기회 전환률(조직별 목록)', dialect: 'tsql', verified: true,
    description: '조직별 활동→영업기회 전환율(%, 소수 형태) — frag_conv_org_lead ÷ frag_conv_org_ac를 FULL OUTER JOIN.',
    input_tables: [], input_columns: [],
    output_columns: ['dealer_nm', 'group_name', 'dept_nm', 'name', 'common_tp_nm', 'cvr_lead_act_mtd'],
    dependencies: ['frag_conv_org_lead', 'frag_conv_org_ac'], business_rule_ids: [],
    sql_template: `SELECT\n    COALESCE(lead.dealer_nm, ac.dealer_nm) AS dealer_nm,\n    COALESCE(lead.group_name, ac.group_name) AS group_name,\n    COALESCE(lead.dept_nm, ac.dept_nm) AS dept_nm,\n    COALESCE(lead.[name], ac.[name]) AS [name],\n    COALESCE(lead.common_tp_nm, ac.common_tp_nm) AS common_tp_nm,\n    CASE WHEN ac.ac_cnt IS NULL OR ac.ac_cnt = 0 THEN NULL\n         ELSE CAST(ISNULL(lead.lead_cnt, 0) AS DECIMAL(18,4)) / ac.ac_cnt\n    END AS cvr_lead_act_mtd\nFROM conv_org_lead AS lead\n    FULL OUTER JOIN conv_org_ac AS ac\n        ON lead.dealer_nm = ac.dealer_nm AND lead.group_name = ac.group_name\n        AND lead.dept_nm = ac.dept_nm AND lead.[name] = ac.[name] AND lead.common_tp_nm = ac.common_tp_nm\nORDER BY dealer_nm, group_name, dept_nm, [name], common_tp_nm`,
