    sql_template: `SELECT\n    COALESCE(la.dealer_nm, lt.dealer_nm) AS dealer_nm,\n    COALESCE(la.group_name, lt.group_name) AS group_name,\n    COALESCE(la.dept_nm, lt.dept_nm) AS dept_nm,\n    COALESCE(la.[name], lt.[name]) AS [name],\n    COALESCE(la.common_tp_nm, lt.common_tp_nm) AS common_tp_nm,\n    CASE WHEN ISNULL(lt.tgt_cnt, 0) = 0 THEN 0.0\n         ELSE CAST(ISNULL(la.lead_cnt, 0) AS float) / lt.tgt_cnt\n    END AS progress_lead_funnel_mtd_sc\nFROM lead_progress_org_actual AS la\n    FULL OUTER JOIN lead_progress_org_target AS lt\n        ON la.dealer_nm = lt.dealer_nm AND la.group_name = lt.group_name\n        AND la.dept_nm = lt.dept_nm AND la.[name] = lt.[name] AND la.common_tp_nm = lt.common_tp_nm\nORDER BY dealer_nm, group_name, dept_nm, [name], common_tp_nm`,
