    sql_template: `SELECT\n    COALESCE(cf.dealer_nm, lf.dealer_nm) AS dealer_nm,\n    COALESCE(cf.group_name, lf.group_name) AS group_name,\n    COALESCE(cf.dept_nm, lf.dept_nm) AS dept_nm,\n    COALESCE(cf.[name], lf.[name]) AS [name],\n    COALESCE(cf.common_tp_nm, lf.common_tp_nm) AS common_tp_nm,\n    CASE WHEN ISNULL(lf.lead_cnt, 0) = 0 THEN NULL\n         ELSE CAST(cf.cntrct_cnt AS float) / lf.lead_cnt\n    END AS cvr_cntrct_lead_mtd\nFROM cntrct_conv_org_lead AS lf\nFULL OUTER JOIN cntrct_conv_org_cntrct AS cf\n    ON lf.dealer_nm = cf.dealer_nm AND lf.group_name = cf.group_name\n    AND lf.dept_nm = cf.dept_nm AND lf.[name] = cf.[name] AND lf.common_tp_nm = cf.common_tp_nm\nORDER BY dealer_nm, group_name, dept_nm, [name], common_tp_nm`,
