    sql_template: `SELECT\n    COALESCE(cf.dealer_nm, t.dealer_nm) AS dealer_nm,\n    COALESCE(cf.group_name, t.group_name) AS group_name,\n    COALESCE(cf.dept_nm, t.dept_nm) AS dept_nm,\n    COALESCE(cf.[name], t.[name]) AS [name],\n    CASE WHEN ISNULL(t.target_cnt, 0) = 0 THEN 1.0\n         ELSE CAST(ISNULL(cf.cntrct_cnt, 0) AS float) / t.target_cnt\n    END AS progress_cntrct_funnel_mtd_sc_cond\nFROM cntrct_progress_org_tgt AS t\nFULL OUTER JOIN cntrct_progress_org_cntrct AS cf\n    ON t.dealer_nm = cf.dealer_nm AND t.group_name = cf.group_name\n    AND t.dept_nm = cf.dept_nm AND t.[name] = cf.[name]\nORDER BY dealer_nm, group_name, dept_nm, [name]`,
