    business_rule_ids: ['br_yearmonth_scope', 'br_qualified_lead_def', 'br_exclude_front_sc', 'br_exclude_staff_names', 'br_exclude_test_users'],
    sql_template: `SELECT COUNT(DISTINCT l.lead_key) AS lead_cnt FROM ktws.FCT_LEAD AS l\n    INNER JOIN ktws.DIM_CALENDAR_KTWS AS lc ON l.lead_reg_dt = lc.[Date]\n    INNER JOIN ktws.DIM_MNG_USER AS u ON l.cl_sc_key = u.sc_key\n    INNER JOIN ktws.DIM_MNG_DEALER AS d ON u.dealer_key = d.dealer_key\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE AS lct ON l.tp_key = lct.tp_key\n    INNER JOIN ktws.DIM_CRM_ACT_TYPE_ORDER AS aord ON lct.common_tp_nm = aord.common_tp_nm\nWHERE lc.[Year] = 2026 AND lc.[MonthNumber] = 4\n    AND ( l.close_dt > '2026-04-30' OR l.close_dt IS NULL OR l.last_retail_sales_dt IS NOT NULL )\n    AND d.dealer_nm IS NOT NULL AND LTRIM(RTRIM(d.dealer_nm)) <> ''\n    AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n    AND (u.[name] NOT IN ('고객지원팀', 'TOYOTA YM') OR u.[name] IS NULL)\n    AND u.user_id NOT IN ('DM5103','DM9999','JB30007','JB30016','KMKS176','KMKS999','JB30067')\n    AND EXISTS (\n        SELECT 1 FROM ktws.FCT_ACTIVITY_v2 AS a\n            INNER JOIN ktws.DIM_CRM_ACT_TYPE AS act ON a.tp_key = act.tp_key\n        WHERE a.lead_key = l.lead_key AND a.sc_key = l.cl_sc_key\n            AND act.common_tp_nm = lct.common_tp_nm AND act.tp_grp_1 IN ('관계형성', '기회창출')\n            AND ( a.act_result IS NULL OR a.act_result <> '부재중' )\n            AND a.act_dt_fr >= '2026-04-01' AND a.act_dt_fr <= '2026-04-30'\n    )`,
