    dependencies: [], business_rule_ids: ['br_exclude_front_sc', 'br_exclude_staff_names', 'br_exclude_test_users'],
    sql_template: `SELECT\n    h.meet_ym_seq AS 회차, h.meet_dt AS 미팅일자, h.chip_status_nm AS 상태,\n    u.dept_nm AS 팀, u.[name] AS SC, h.contact_nm AS 상담자, h.hold_type_nm AS 확보유형,\n    v.variant_nm AS 관심차종, h.hot_reg_dt AS HOT등록일, h.hboard_reg_dt AS BOARD등록일,\n    h.next_plant_dt AS 다음활동예정일, h.contract_ratio AS 금주계약가능성, h.remark AS 메모,\n    h.comp_model_nm AS 경쟁차종, h.own_model_nm AS 현재보유차종, h.own_model_pdt AS 현재보유차종상세,\n    h.pay_type_nm AS 지불유형\nFROM ktws.FCT_HBOARD_MEETING h\nLEFT JOIN ktws.DIM_MNG_USER u ON u.sc_key = h.mng_sc_key\nLEFT JOIN ktws.DIM_VEHIC_SPEC_VAR v ON v.var_key = h.int_var_key\nWHERE YEAR(h.meet_dt) = 2026\n  AND (u.facade_sc_yn <> '창구SC' OR u.facade_sc_yn IS NULL)\n  AND (u.dept_nm NOT IN ('고객지원팀', 'TOYOTA YM') OR u.dept_nm IS NULL)\n  AND (u.user_id NOT IN ('DM5103','DM9999','JB30007','JB30016','KMKS176','KMKS999','JB30067') OR u.user_id IS NULL)\nORDER BY h.meet_dt DESC, h.contact_nm`,
